def build_insight_icp_definition_framework():
    """Batch 6: ICP Definition Framework for GTM Engineers."""
    title = "ICP Definition Framework for GTM Engineers"
    description = pad_description(
        "A structured framework for defining your Ideal Customer Profile using enrichment data, firmographics, and buying signals."
    )
    crumbs = [("Home", "/"), ("Insights", "/insights/"), ("ICP Definition Framework", None)]
    bc_html = breadcrumb_html(crumbs)
