def _load_glossary_content(slug):
    """Load glossary content from content/glossary.py by slug key."""
    import importlib
    import importlib.util
    content_dir = os.path.join(PROJECT_DIR, "content")
    module_path = os.path.join(content_dir, "glossary.py")
    try:
        spec = importlib.util.spec_from_file_location("glossary", module_path)
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        return mod.GLOSSARY_TERMS.get(slug, {})
    except (ImportError, AttributeError, FileNotFoundError) as e:
        print(f"  WARNING: Could not load content/glossary.py key={slug}: {e}")
        return {}


def glossary_related_links(current_slug):
    """Generate related links for a glossary term page."""
    links = [("/glossary/", "Glossary Index")]
    # Other glossary terms from same category
    current_cat = None
    for t in GLOSSARY_TERMS:
        if t["slug"] == current_slug:
            current_cat = t["category"]
            break
    for t in GLOSSARY_TERMS:
        if t["slug"] != current_slug and t["category"] == current_cat:
            links.append((f"/glossary/{t['slug']}/", t["term"]))
    # Add some cross-vertical links
    links.append(("/tools/", "GTM Engineering Tools"))
    links.append(("/salary/", "Salary Data"))
    links.append(("/careers/", "Career Guides"))
    links = links[:12]
    items = ""
    for href, label in links:
        items += f'<a href="{href}" class="related-link-card">{label}</a>\n'
    return f'''<section class="related-links">
    <h2>Related Glossary Terms</h2>
    <div class="related-links-grid">
        {items}
    </div>
</section>'''


def build_job_board():
    """Generate /jobs/index.html with job cards, stats banner, and client-side filters."""
    print("\n  Building job board...")

    # Load jobs data
    jobs_path = os.path.join(PROJECT_DIR, "data", "jobs.json")
    try:
        with open(jobs_path, "r", encoding="utf-8") as f:
            raw = json.load(f)
        # Support both flat list and nested {"jobs": [...]} formats
        jobs = raw.get("jobs", raw) if isinstance(raw, dict) else raw
    except (FileNotFoundError, json.JSONDecodeError):
        jobs = []

    crumbs = [("Home", "/"), ("Jobs", None)]
    bc_html = breadcrumb_html(crumbs)
    bc_schema = get_breadcrumb_schema(crumbs)

    if not jobs:
        body = f'''{bc_html}
<section class="salary-header">
    <div class="salary-header-inner">
        <div class="salary-eyebrow">Job Board</div>
        <h1>GTM Engineer Jobs</h1>
        <p>Curated GTM Engineering roles from across the industry. Updated from 3,000+ tracked B2B SaaS job postings.</p>
    </div>
</section>
{content_figure_html("jobs")}
<div class="salary-content">
    <p>No current postings. Check back soon or subscribe to the newsletter for job alerts.</p>
    <p>While you wait, explore <a href="/salary/">GTM Engineer salary data</a>, learn <a href="/careers/is-gtm-engineering-real-career/">what a GTM Engineer does</a>, browse our <a href="/tools/">tool reviews</a>, or check the <a href="/glossary/">glossary</a> for industry terms.</p>
</div>
'''
        body += newsletter_cta_html("Get GTM Engineer job alerts and salary data delivered weekly.")
        page = get_page_wrapper(
            title="GTM Engineer Jobs: Open Roles and Hiring Data",
            description=pad_description("Browse curated GTM Engineer job postings with salary data, remote filters, and hiring trends. Updated from 3,000+ tracked B2B SaaS positions."),
            canonical_path="/jobs/",
            body_content=body,
            active_path="/jobs/",
            extra_head=bc_schema,
            body_class="page-inner",
        )
        write_page("jobs/index.html", page)
        print("  Built: jobs/index.html (no jobs data)")
        return

    # Compute aggregate stats
    total_roles = len(jobs)
    salaries = [j.get("salary_min") or j.get("min_amount") for j in jobs if (j.get("salary_min") or j.get("min_amount"))] + [j.get("salary_max") or j.get("max_amount") for j in jobs if (j.get("salary_max") or j.get("max_amount"))]
    median_salary = sorted(salaries)[len(salaries) // 2] if salaries else 0
    median_display = f"${median_salary // 1000}K" if median_salary else "N/A"
    remote_count = sum(1 for j in jobs if j.get("remote"))
    pct_remote = round(remote_count / total_roles * 100) if total_roles else 0
    # Top hiring city
    city_counts = {}
    for j in jobs:
        loc = j.get("location", "Unknown")
        city_counts[loc] = city_counts.get(loc, 0) + 1
    top_city = max(city_counts, key=city_counts.get) if city_counts else "N/A"

    # Unique locations and seniorities for filters
    locations = sorted(set(j.get("location", "") for j in jobs))
    seniorities = ["Junior", "Mid", "Senior", "Lead", "Staff", "Director", "VP"]

    # Stats banner
    stats_html = f'''<div class="salary-stats" style="max-width: 900px; grid-template-columns: repeat(4, 1fr);">
    <div class="salary-stat-card">
        <span class="stat-value">{total_roles}</span>
        <span class="stat-label">Open Roles</span>
    </div>
    <div class="salary-stat-card">
        <span class="stat-value">{median_display}</span>
        <span class="stat-label">Median Salary</span>
    </div>
    <div class="salary-stat-card">
        <span class="stat-value">{pct_remote}%</span>
        <span class="stat-label">Remote</span>
    </div>
    <div class="salary-stat-card">
        <span class="stat-value">{top_city}</span>
        <span class="stat-label">Top Hiring City</span>
    </div>
</div>'''

    # Location datalist
    location_options = "\n".join(f'<option value="{loc}">' for loc in locations)
    seniority_options = '<option value="">All Seniority</option>\n' + "\n".join(
        f'<option value="{s}">{s}</option>' for s in seniorities
    )

    # Filter bar
    filter_html = f'''<div class="job-filters">
    <select id="filter-seniority" onchange="filterJobs()" aria-label="Filter by seniority">
        {seniority_options}
    </select>
    <input type="text" id="filter-location" list="location-list" placeholder="Filter by location" oninput="filterJobs()" aria-label="Filter by location">
    <datalist id="location-list">
        {location_options}
    </datalist>
    <label class="job-filter-toggle">
        <input type="checkbox" id="filter-remote" onchange="filterJobs()"> Remote only
    </label>
</div>'''

    # Relative date helper
    from datetime import datetime as dt
    today = dt.now()

    def relative_date(date_str):
        try:
            d = dt.strptime(date_str, "%Y-%m-%d")
            delta = (today - d).days
            if delta == 0:
                return "Today"
            if delta == 1:
                return "1 day ago"
            if delta < 7:
                return f"{delta} days ago"
            if delta < 14:
                return "1 week ago"
            if delta < 30:
                return f"{delta // 7} weeks ago"
            return f"{delta // 30} months ago"
        except (ValueError, TypeError):
            return "Recently"

    # Job cards
    cards_html = ""
    for j in jobs:
        title = j.get("title", "GTM Engineer")
        company = j.get("company", "")
        location = j.get("location", "")
        salary = j.get("salary_display", "Salary not disclosed")
        remote = j.get("remote", False)
        seniority = j.get("seniority", "Mid")
        url = j.get("url", "#")
        posted = j.get("posted_date", "")
        source = j.get("source", "")

        remote_badge = '<span class="job-badge-remote">Remote</span>' if remote else ""
        seniority_badge = f'<span class="job-badge-seniority">{seniority}</span>'
        source_badge = f'<span class="job-badge-source">{source}</span>' if source else ""
        posted_relative = relative_date(posted)

        cards_html += f'''<div class="job-card" data-seniority="{seniority}" data-location="{location}" data-remote="{'true' if remote else 'false'}">
    <div class="job-card-header">
        <h3 class="job-card-title"><a href="{url}" target="_blank" rel="noopener">{title}</a></h3>
        <div class="job-card-badges">{seniority_badge} {remote_badge}</div>
    </div>
    <div class="job-card-meta">
        <span class="job-card-company">{company}</span>
        <span class="job-card-location">{location}</span>
    </div>
    <div class="job-card-footer">
        <span class="job-salary">{salary}</span>
        <span class="job-card-posted">{posted_relative}</span>
        {source_badge}
    </div>
</div>
'''

    # Inline filter JS
    filter_js = '''<script>
function filterJobs() {
    var seniority = document.getElementById('filter-seniority').value.toLowerCase();
    var location = document.getElementById('filter-location').value.toLowerCase();
    var remoteOnly = document.getElementById('filter-remote').checked;
    var cards = document.querySelectorAll('.job-card');
    var visible = 0;
    cards.forEach(function(card) {
        var matchSeniority = !seniority || card.getAttribute('data-seniority').toLowerCase() === seniority;
        var matchLocation = !location || card.getAttribute('data-location').toLowerCase().indexOf(location) !== -1;
        var matchRemote = !remoteOnly || card.getAttribute('data-remote') === 'true';
        if (matchSeniority && matchLocation && matchRemote) {
            card.style.display = '';
            visible++;
        } else {
            card.style.display = 'none';
        }
    });
    var counter = document.getElementById('job-count');
    if (counter) counter.textContent = visible + ' role' + (visible !== 1 ? 's' : '');
}
</script>'''

    body = f'''{bc_html}
<section class="salary-header">
    <div class="salary-header-inner">
        <div class="salary-eyebrow">Job Board</div>
        <h1>GTM Engineer Jobs</h1>
        <p>Curated GTM Engineering roles from across the industry. Updated from 3,000+ tracked B2B SaaS job postings.</p>
    </div>
</section>

{stats_html}

{content_figure_html("jobs")}

<div class="salary-content">
    <p style="margin-bottom: 1.5rem;">Explore <a href="/salary/">GTM Engineer salary data</a> to benchmark compensation, read <a href="/careers/is-gtm-engineering-real-career/">what a GTM Engineer does</a> for role context, browse our <a href="/tools/">tool reviews</a> to build your stack, or check the <a href="/glossary/">glossary</a> for industry terms.</p>

    {filter_html}

    <p id="job-count" style="font-size: var(--gtme-text-sm); color: var(--gtme-text-secondary); margin-bottom: var(--gtme-space-4);">{total_roles} role{"s" if total_roles != 1 else ""}</p>

    <div class="job-card-grid">
        {cards_html}
    </div>
</div>

{filter_js}
'''
    body += newsletter_cta_html("Get GTM Engineer job alerts and salary data delivered weekly.")

    page = get_page_wrapper(
        title="GTM Engineer Jobs: Open Roles and Hiring Data",
        description=pad_description("Browse curated GTM Engineer job postings with salary data, remote filters, and hiring trends. Updated from 3,000+ tracked B2B SaaS positions."),
        canonical_path="/jobs/",
        body_content=body,
        active_path="/jobs/",
        extra_head=bc_schema,
        body_class="page-inner",
    )
    write_page("jobs/index.html", page)
    print(f"  Built: jobs/index.html ({total_roles} jobs)")


def build_glossary_index():
    """Generate /glossary/index.html with all 50 terms grouped by category."""
    print("\n  Building glossary index...")
    crumbs = [("Home", "/"), ("Glossary", None)]
    bc_html = breadcrumb_html(crumbs)
    bc_schema = get_breadcrumb_schema(crumbs)

    # Group terms by category
    categories_order = [
        "Data & Enrichment",
        "Outbound & Sequencing",
        "Automation & Workflows",
        "Analytics & Signals",
        "Career & Industry",
        "CRM & Pipeline",
        "AI & LLM",
    ]
    terms_by_cat = {}
    for t in GLOSSARY_TERMS:
        cat = t["category"]
        if cat not in terms_by_cat:
            terms_by_cat[cat] = []
        terms_by_cat[cat].append(t)

    # Sort terms alphabetically within each category
    for cat in terms_by_cat:
        terms_by_cat[cat].sort(key=lambda x: x["term"].lower())

    # Build category sections
    category_sections = ""
    for cat in categories_order:
        terms = terms_by_cat.get(cat, [])
        if not terms:
            continue
        cards = ""
        for t in terms:
            content = _load_glossary_content(t["slug"])
            definition = content.get("definition", "")
            cards += f'''<a href="/glossary/{t["slug"]}/" class="salary-index-card">
    <h3>{t["term"]}</h3>
    <p>{definition}</p>
</a>
'''
        category_sections += f'''
    <h2>{cat}</h2>
    <div class="salary-index-grid">
        {cards}
    </div>
'''

    body = f'''{bc_html}
<section class="salary-header">
    <div class="salary-header-inner">
        <div class="salary-eyebrow">Reference</div>
        <h1>GTM Engineering Glossary</h1>
        <p>56 terms every GTM Engineer should know. Definitions, real examples, and links to deeper resources across tools, salary data, and career guides.</p>
    </div>
</section>

{content_figure_html("glossary")}

<div class="salary-content">
    {category_sections}
</div>
'''
    body += newsletter_cta_html("Get weekly GTM Engineering terms, tool intel, and career insights.")

    page = get_page_wrapper(
        title="GTM Engineering Glossary: 56 Key Terms",
        description=pad_description("Master the GTM Engineering vocabulary. 56 key terms with definitions, examples, and cross-links to tool reviews, salary data, and career guides."),
        canonical_path="/glossary/",
        body_content=body,
        active_path="/glossary/",
        extra_head=bc_schema,
        body_class="page-inner",
    )
    write_page("glossary/index.html", page)
    print("  Built: glossary/index.html")


def generate_glossary_term(term_data):
    """Generate a single glossary term page at /glossary/[slug]/."""
    slug = term_data["slug"]
    term = term_data["term"]
    category = term_data["category"]

    content = _load_glossary_content(slug)
    if not content:
        print(f"  SKIP (no content): glossary/{slug}")
        return

    definition = content.get("definition", "")
    body_text = content.get("body", "")
    related_links = content.get("related_links", [])

    # Breadcrumbs
    crumbs = [("Home", "/"), ("Glossary", "/glossary/"), (term, None)]
    bc_html = breadcrumb_html(crumbs)
    bc_schema = get_breadcrumb_schema(crumbs)

    # Related links from content module
    content_related = ""
    if related_links:
        link_items = ""
        for href, label in related_links:
            link_items += f'<a href="{href}" class="related-link-card">{label}</a>\n'
        content_related = f'''<section class="related-links" style="margin-top: 2rem;">
    <h2>Learn More</h2>
    <div class="related-links-grid">
        {link_items}
    </div>
</section>'''

    body = f'''{bc_html}
<section class="salary-header">
    <div class="salary-header-inner">
        <div class="salary-eyebrow">{category} &middot; Glossary</div>
        <h1>What is {term}?</h1>
    </div>
</section>

<div class="salary-content">
    <div style="background: var(--gtme-bg-tinted); border-left: 4px solid var(--gtme-accent); padding: 1.25rem 1.5rem; border-radius: 0 8px 8px 0; margin-bottom: 2rem;">
        <p style="font-size: 1.1rem; line-height: 1.65; margin: 0; color: var(--gtme-text-primary);"><strong>Definition:</strong> {definition}</p>
    </div>

    {body_text}

    {content_related}
</div>

{glossary_related_links(slug)}
'''
    body += newsletter_cta_html("Get weekly GTM Engineering terms and tool intel delivered to your inbox.")

    # Target 50-60 chars for full title (including " - GTME Pulse" suffix)
    suffix = " - GTME Pulse"
    # Strip parenthetical abbreviations for shorter title variants
    term_short = re.sub(r'\s*\([^)]+\)', '', term).strip()
    candidates = [
        f"What is {term}? GTM Engineering Glossary",
        f"What is {term}? GTM Engineer Glossary",
        f"What is {term}? GTM Glossary Term",
        f"What is {term}? GTM Glossary",
        f"What is {term_short}? GTM Engineer Glossary",
        f"What is {term_short}? GTM Glossary",
        f"{term}: GTM Engineer Definition",
        f"{term} Defined for GTM Engineers",
        f"{term}: Definition and GTM Use Cases",
        f"{term_short}: GTM Engineer Definition",
        f"{term_short} Defined for GTM Engineers",
        f"{term} Defined",
    ]
    title = None
    for candidate in candidates:
        full_len = len(candidate + suffix)
        if 50 <= full_len <= 60:
            title = candidate
            break
    if not title:
        title = min(candidates, key=lambda c: abs(len(c + suffix) - 55))
    meta_desc = pad_description(f"What is {term}? Clear definition with real examples and use cases for GTM Engineers. Part of the GTME Pulse glossary.")

    page = get_page_wrapper(
        title=title,
        description=meta_desc,
        canonical_path=f"/glossary/{slug}/",
        body_content=body,
        active_path="/glossary/",
        extra_head=bc_schema,
        body_class="page-inner",
    )
    write_page(f"glossary/{slug}/index.html", page)


def build_glossary_terms():
    """Build all individual glossary term pages."""
    print("  Building glossary term pages...")
    for term_data in GLOSSARY_TERMS:
        generate_glossary_term(term_data)
    print(f"  Built: {len(GLOSSARY_TERMS)} glossary term pages")


